import React, { useState, useEffect } from 'react';
import type { Order, OrderFormData } from '../types';
import { COUNTRIES, PRODUCTS, ORDER_STATUSES, CREATED_BY } from '../utils/constants';

interface Props {
  order?: Order | null;
  onSubmit: (data: OrderFormData) => Promise<void>;
  onClose: () => void;
}

type FormErrors = Partial<Record<keyof OrderFormData, string>>;

const EMPTY_FORM: OrderFormData = {
  firstName: '', lastName: '', email: '', phone: '',
  streetAddress: '', city: '', state: '', postalCode: '',
  country: 'United States', product: 'Fiber Internet 300 Mbps',
  quantity: 1, unitPrice: 0, status: 'Pending',
  createdBy: 'Mr. Michael Harris',
};

export const OrderForm: React.FC<Props> = ({ order, onSubmit, onClose }) => {
  const [form, setForm] = useState<OrderFormData>(EMPTY_FORM);
  const [errors, setErrors] = useState<FormErrors>({});
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    if (order) {
      const { id, orderId, orderDate, totalAmount, createdAt, updatedAt, ...rest } = order;
      setForm(rest as OrderFormData);
    } else {
      setForm(EMPTY_FORM);
    }
    setErrors({});
  }, [order]);

  const totalAmount = (form.quantity || 0) * (form.unitPrice || 0);

  const set = (field: keyof OrderFormData, value: unknown) => {
    setForm(prev => ({ ...prev, [field]: value }));
    if (errors[field]) setErrors(prev => ({ ...prev, [field]: undefined }));
  };

  const validate = (): boolean => {
    const mandatory: (keyof OrderFormData)[] = [
      'firstName', 'lastName', 'email', 'phone', 'streetAddress',
      'city', 'state', 'postalCode', 'country', 'product',
      'quantity', 'unitPrice', 'status', 'createdBy',
    ];
    const newErrors: FormErrors = {};
    mandatory.forEach(f => {
      const v = form[f];
      if (v === '' || v === null || v === undefined) {
        newErrors[f] = 'Please fill the field';
      }
    });
    if (form.quantity < 1) newErrors.quantity = 'Quantity cannot be less than 1';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;
    setSubmitting(true);
    try {
      await onSubmit(form);
      onClose();
    } finally {
      setSubmitting(false);
    }
  };

  const Field = ({
    label, field, type = 'text', required = true, children, span = 1
  }: {
    label: string; field: keyof OrderFormData; type?: string;
    required?: boolean; children?: React.ReactNode; span?: number;
  }) => (
    <div style={{ gridColumn: `span ${span}` }}>
      <label style={styles.label}>{label}{required && <span style={{ color: '#EF4444' }}> *</span>}</label>
      {children || (
        <input
          type={type}
          value={String(form[field] ?? '')}
          onChange={e => set(field, type === 'number' ? Number(e.target.value) : e.target.value)}
          style={{ ...styles.input, ...(errors[field] ? styles.inputError : {}) }}
          placeholder={`Enter ${label.toLowerCase()}`}
        />
      )}
      {errors[field] && <p style={styles.errorMsg}>{errors[field]}</p>}
    </div>
  );

  const Select = ({
    label, field, options, required = true
  }: {
    label: string; field: keyof OrderFormData;
    options: string[]; required?: boolean;
  }) => (
    <Field label={label} field={field} required={required}>
      <select
        value={String(form[field])}
        onChange={e => set(field, e.target.value)}
        style={{ ...styles.input, ...(errors[field] ? styles.inputError : {}) }}
      >
        {options.map(o => <option key={o} value={o}>{o}</option>)}
      </select>
    </Field>
  );

  return (
    <div style={styles.overlay} onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={styles.modal}>
        {/* Header */}
        <div style={styles.modalHeader}>
          <div>
            <h2 style={styles.modalTitle}>{order ? 'Edit Order' : 'Create Order'}</h2>
            <p style={styles.modalSubtitle}>{order ? `Editing ${order.orderId}` : 'Fill in the details to create a new order'}</p>
          </div>
          <button onClick={onClose} style={styles.closeBtn}>✕</button>
        </div>

        <form onSubmit={handleSubmit} noValidate>
          <div style={styles.formBody}>
            {/* Customer Information */}
            <div style={styles.section}>
              <div style={styles.sectionHeader}>
                <div style={styles.sectionDot} />
                <h3 style={styles.sectionTitle}>Customer Information</h3>
              </div>
              <div style={styles.grid2}>
                <Field label="First name" field="firstName" />
                <Field label="Last name" field="lastName" />
                <Field label="Email ID" field="email" type="email" />
                <Field label="Phone number" field="phone" />
                <Field label="Street address" field="streetAddress" span={2} />
                <Field label="City" field="city" />
                <Field label="State / Province" field="state" />
                <Field label="Postal code" field="postalCode" />
                <Select label="Country" field="country" options={COUNTRIES} />
              </div>
            </div>

            {/* Order Information */}
            <div style={styles.section}>
              <div style={styles.sectionHeader}>
                <div style={{ ...styles.sectionDot, background: '#8B5CF6' }} />
                <h3 style={styles.sectionTitle}>Order Information</h3>
              </div>
              <div style={styles.grid2}>
                <Select label="Choose product" field="product" options={PRODUCTS} />
                <Select label="Status" field="status" options={ORDER_STATUSES} />

                <Field label="Quantity" field="quantity" type="number">
                  <input
                    type="number"
                    min={1}
                    value={form.quantity}
                    onChange={e => set('quantity', Math.max(1, Number(e.target.value)))}
                    style={{ ...styles.input, ...(errors.quantity ? styles.inputError : {}) }}
                  />
                </Field>

                <Field label="Unit price" field="unitPrice" type="number">
                  <div style={styles.prefixWrap}>
                    <span style={styles.prefix}>$</span>
                    <input
                      type="number"
                      min={0}
                      step={0.01}
                      value={form.unitPrice}
                      onChange={e => set('unitPrice', Number(e.target.value))}
                      style={{ ...styles.input, paddingLeft: '2rem', ...(errors.unitPrice ? styles.inputError : {}) }}
                    />
                  </div>
                </Field>

                {/* Total Amount (read-only) */}
                <div>
                  <label style={styles.label}>Total amount <span style={{ color: '#EF4444' }}>*</span></label>
                  <div style={styles.readOnly}>
                    <span style={{ color: '#6B7280', fontSize: '13px' }}>Auto-calculated</span>
                    <span style={{ fontWeight: 600, fontSize: '16px', color: '#111827' }}>
                      ${totalAmount.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                    </span>
                  </div>
                </div>

                <Select label="Created by" field="createdBy" options={CREATED_BY} />
              </div>
            </div>
          </div>

          {/* Footer */}
          <div style={styles.modalFooter}>
            <button type="button" onClick={onClose} style={styles.cancelBtn}>Cancel</button>
            <button type="submit" disabled={submitting} style={styles.submitBtn}>
              {submitting ? 'Saving...' : order ? 'Update Order' : 'Create Order'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

